create table categories (created_at timestamp(6) with time zone, updated_at timestamp(6) with time zone, id varchar(36) not null, category_name varchar(100) not null unique, category_id varchar(255) not null unique, created_by varchar(255) not null, reason varchar(255) not null, primary key (id));
create table products (is_active boolean not null, price float(53) not null, stocks float(53) not null, warranty_period float(53) not null, created_at timestamp(6) with time zone, expire_date timestamp(6) with time zone not null, manufacture_date timestamp(6) with time zone not null, updated_at timestamp(6) with time zone, id varchar(36) not null, brand_name varchar(255) not null, category varchar(255) not null, category_code varchar(255) not null, description text not null, item_code varchar(255) not null unique, item_name varchar(255) not null, manufacturer_code varchar(255) not null, manufacturer_name varchar(255) not null, product_image text not null, updated_by varchar(255) not null, warranty_claim_process varchar(255) not null, warranty_details varchar(255) not null, primary key (id));
create table received_stocks (qty float(53) not null, created_at timestamp(6) with time zone, updated_at timestamp(6) with time zone, id varchar(36) not null, received_product_name varchar(100) not null unique, category varchar(255) not null, created_by varchar(255) not null, received_productid varchar(255) not null unique, remark varchar(255) not null, primary key (id));
